export function getStationBySlug(slug: string): StationConfig | undefined {
  return MISSISSIPPI_STATIONS.find(s => s.slug === slug)
}

export function getAllSlugs(): string[] {
  return MISSISSIPPI_STATIONS.map(s => s.slug)
}
